class Solution:
    def minimumCost(self, nums: List[int]) -> int:
        n = len(nums)
        # We need to split into 3 contiguous subarrays, so we need to choose 2 split points
        # The first subarray is always from index 0 to i, the second from i+1 to j, and the third from j+1 to n-1
        # The cost is the first element of each subarray, so we need to minimize nums[0] + nums[i+1] + nums[j+1]
        # We can iterate over all possible i and j to find the minimum sum

        min_sum = float('inf')
        for i in range(1, n - 1):
            for j in range(i + 1, n):
                cost = nums[0] + nums[i] + nums[j]
                if cost < min_sum:
                    min_sum = cost
        return min_sum
